mapper.select:
select count(1)
from recommend_slots

  and deleted = false

    and page_code = #{pageCode}


    and status = #{status}

select slot_id, slot_name, page_code, resource_type, target_title, sort_no, status, created_at, updated_at, created_by, updated_by, deleted
from recommend_slots

  and deleted = false

    and page_code = #{pageCode}


    and status = #{status}


order by sort_no asc, slot_id asc
limit #{pageSize} offset #{offset}

mapper.insert:
insert into recommend_slots (
  slot_name, page_code, resource_type, target_title, sort_no, status,
  created_at, updated_at, created_by, updated_by, deleted
)
values (
  #{slotName}, #{pageCode}, #{resourceType}, #{targetTitle}, #{sortNo}, #{status},
  #{createdAt}, #{updatedAt}, #{createdBy}, #{updatedBy}, #{deleted}
)

mapper.update:
update recommend_slots
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where slot_id = #{slotId}
  and deleted = false
